+/**
+ * Webhook notification adapter.
+ *
+ * Implements NotificationAdapter for the 'webhook' channel.
+ * POSTs a JSON payload to a configured URL. Uses a pluggable
+ * WebhookTransport so production HTTP clients can be swapped in.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookConfig {
+  /** Default webhook URL (used when payload.recipient is not a URL) */
+  defaultUrl?: string;
+  /** Maximum retries on transient failure */
+  maxRetries?: number;
+  /** Timeout in milliseconds for each request */
+  timeoutMs?: number;
+  /** Optional secret for signing payloads */
+  secret?: string;
+}
+
+/**
+ * The JSON body sent to the webhook endpoint.
+ */
+export interface WebhookRequestBody {
+  notificationId: string;
+  type: string;
+  channel: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority: string;
+  metadata: Record<string, string>;
+  createdAt: string;
+}
+
+/**
+ * Transport interface for sending webhook HTTP requests.
+ * Swap this out for production HTTP clients (fetch, axios, etc.).
+ */
+export interface WebhookTransport {
+  post(url: string, body: WebhookRequestBody, config: WebhookConfig): Promise<{ success: boolean; statusCode?: number; error?: string }>;
+  isReachable(): Promise<boolean>;
+}
+
+/**
+ * Default in-memory transport — stores posted webhooks for testing/dev.
+ */
+export class InMemoryWebhookTransport implements WebhookTransport {
+  private posted: Array<{ url: string; body: WebhookRequestBody }> = [];
+
+  async post(url: string, body: WebhookRequestBody): Promise<{ success: boolean; statusCode?: number; error?: string }> {
+    this.posted.push({ url, body });
+    return { success: true, statusCode: 200 };
+  }
+
+  async isReachable(): Promise<boolean> {
+    return true;
+  }
+
+  getPostedWebhooks(): Array<{ url: string; body: WebhookRequestBody }> {
+    return [...this.posted];
+  }
+
+  clearPostedWebhooks(): void {
+    this.posted = [];
+  }
+}
+
+/**
+ * Resolve the webhook URL from the payload recipient or fall back to the default.
+ * If the recipient looks like a URL (starts with http:// or https://), use it directly.
+ * Otherwise, use the default URL from config.
+ */
+function resolveUrl(recipient: string, config: WebhookConfig, logger: Logger): string {
+  const trimmed = recipient.trim();
+  if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
+    return trimmed;
+  }
+  if (config.defaultUrl) {
+    logger.info(`Recipient "${trimmed}" is not a URL — using default webhook URL`);
+    return config.defaultUrl;
+  }
+  throw new Error(`Recipient "${trimmed}" is not a valid URL and no default webhook URL is configured`);
+}
+
+/**
+ * Format a NotificationPayload into the JSON body for the webhook POST.
+ */
+function formatRequestBody(payload: NotificationPayload): WebhookRequestBody {
+  return {
+    notificationId: payload.id,
+    type: payload.type,
+    channel: payload.channel,
+    recipient: payload.recipient,
+    subject: payload.subject,
+    body: payload.body,
+    priority: payload.priority,
+    metadata: payload.metadata,
+    createdAt: payload.createdAt.toISOString(),
+  };
+}
+
+export class WebhookAdapter implements NotificationAdapter {
+  readonly channel = 'webhook' as const;
+  private logger = new Logger('WebhookAdapter');
+  private transport: WebhookTransport;
+  private sent: NotificationPayload[] = [];
+  private maxRetries: number;
+
+  constructor(
+    private config: WebhookConfig,
+    transport?: WebhookTransport,
+  ) {
+    this.transport = transport ?? new InMemoryWebhookTransport();
+    this.maxRetries = config.maxRetries ?? 2;
+  }
+
+  /**
+   * Format the notification as JSON and POST it to the webhook URL.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    this.logger.info(
+      `Sending webhook for "${payload.subject}" to ${payload.recipient}`,
+    );
+
+    try {
+      const url = resolveUrl(payload.recipient, this.config, this.logger);
+      const body = formatRequestBody(payload);
+
+      const transportResult = await this.sendWithRetry(url, body);
+
+      if (!transportResult.success) {
+        return {
+          notificationId: payload.id,
+          channel: 'webhook',
+          success: false,
+          error: transportResult.error ?? 'Webhook delivery failed',
+          deliveredAt: new Date(),
+        };
+      }
+
+      this.sent.push(payload);
+
+      return {
+        notificationId: payload.id,
+        channel: 'webhook',
+        success: true,
+        deliveredAt: new Date(),
+      };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : String(err);
+      this.logger.error(`Webhook send failed: ${message}`);
+      return {
+        notificationId: payload.id,
+        channel: 'webhook',
+        success: false,
+        error: message,
+        deliveredAt: new Date(),
+      };
+    }
+  }
+
+  /**
+   * Check if the webhook transport is available.
+   */
+  async isAvailable(): Promise<boolean> {
+    try {
+      return await this.transport.isReachable();
+    } catch {
+      return false;
+    }
+  }
+
+  /**
+   * Get all successfully sent payloads. Useful for testing.
+   */
+  getSentWebhooks(): NotificationPayload[] {
+    return [...this.sent];
+  }
+
+  /**
+   * Clear sent webhooks. Useful for testing.
+   */
+  clearSentWebhooks(): void {
+    this.sent = [];
+  }
+
+  /**
+   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
+   */
+  getTransport(): WebhookTransport {
+    return this.transport;
+  }
+
+  /**
+   * Attempt to send with retries on transient failure.
+   */
+  private async sendWithRetry(
+    url: string,
+    body: WebhookRequestBody,
+  ): Promise<{ success: boolean; error?: string }> {
+    let lastError: string | undefined;
+
+    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
+      const result = await this.transport.post(url, body, this.config);
+      if (result.success) {
+        return result;
+      }
+      lastError = result.error;
+      this.logger.warn(
+        `Webhook delivery attempt ${attempt + 1} failed: ${lastError}`,
+      );
+    }
+
+    return { success: false, error: lastError };
+  }
+}

