import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type {
  WebhookTransport,
  WebhookRequestBody,
  WebhookConfig,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'webhook',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    metadata: {},
    createdAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter({}, transport);
  });

  describe('channel', () => {
    it('should report channel as webhook', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('isAvailable', () => {
    it('should return true when transport is reachable', async () => {
      expect(await adapter.isAvailable()).toBe(true);
    });

    it('should return false when transport throws', async () => {
      const failTransport: WebhookTransport = {
        post: async () => ({ success: true, statusCode: 200 }),
        isReachable: async () => { throw new Error('network error'); },
      };
      const failAdapter = new WebhookAdapter({}, failTransport);
      expect(await failAdapter.isAvailable()).toBe(false);
    });
  });

  describe('send', () => {
    it('should send successfully and track the payload', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      expect(adapter.getSentWebhooks()).toHaveLength(1);
      expect(adapter.getSentWebhooks()[0]?.id).toBe('notif-0001');
    });

    it('should POST correct JSON body to the webhook URL', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const posted = transport.getPostedWebhooks();
      expect(posted).toHaveLength(1);
      expect(posted[0]?.url).toBe('https://hooks.example.com/notify');
      expect(posted[0]?.body.notificationId).toBe('notif-0001');
      expect(posted[0]?.body.type).toBe('order-confirmation');
      expect(posted[0]?.body.channel).toBe('webhook');
      expect(posted[0]?.body.recipient).toBe('https://hooks.example.com/notify');
      expect(posted[0]?.body.subject).toBe('Order Confirmation: order-1');
      expect(posted[0]?.body.body).toContain('Widget x2');
      expect(posted[0]?.body.priority).toBe('normal');
      expect(posted[0]?.body.createdAt).toBe('2026-01-15T12:00:00.000Z');
    });

    it('should return failure when transport fails', async () => {
      const failTransport: WebhookTransport = {
        post: async () => ({ success: false, statusCode: 500, error: 'Internal Server Error' }),
        isReachable: async () => true,
      };
      const failAdapter = new WebhookAdapter({ maxRetries: 0 }, failTransport);

      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Internal Server Error');
    });

    it('should return failure when recipient is not a URL and no default is configured', async () => {
      const payload = makePayload({ recipient: 'user-123' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('not a valid URL');
    });

    it('should use defaultUrl when recipient is not a URL', async () => {
      const defaultAdapter = new WebhookAdapter(
        { defaultUrl: 'https://default.example.com/webhook' },
        transport,
      );

      const payload = makePayload({ recipient: 'user-123' });
      const result = await defaultAdapter.send(payload);

      expect(result.success).toBe(true);
      const posted = transport.getPostedWebhooks();
      expect(posted[0]?.url).toBe('https://default.example.com/webhook');
    });

    it('should use recipient as URL when it starts with https://', async () => {
      const payload = makePayload({ recipient: 'https://custom.example.com/hook' });
      await adapter.send(payload);

      const posted = transport.getPostedWebhooks();
      expect(posted[0]?.url).toBe('https://custom.example.com/hook');
    });

    it('should use recipient as URL when it starts with http://', async () => {
      const payload = makePayload({ recipient: 'http://local.test/hook' });
      await adapter.send(payload);

      const posted = transport.getPostedWebhooks();
      expect(posted[0]?.url).toBe('http://local.test/hook');
    });
  });

  describe('retry logic', () => {
    it('should retry on failure up to maxRetries', async () => {
      let attempts = 0;
      const flakyTransport: WebhookTransport = {
        post: async () => {
          attempts++;
          if (attempts < 3) {
            return { success: false, statusCode: 503, error: 'Service Unavailable' };
          }
          return { success: true, statusCode: 200 };
        },
        isReachable: async () => true,
      };

      const retryAdapter = new WebhookAdapter({ maxRetries: 2 }, flakyTransport);
      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(attempts).toBe(3); // 1 initial + 2 retries
    });

    it('should give up after maxRetries exhausted', async () => {
      const failTransport: WebhookTransport = {
        post: async () => ({ success: false, statusCode: 500, error: 'always fails' }),
        isReachable: async () => true,
      };

      const retryAdapter = new WebhookAdapter({ maxRetries: 1 }, failTransport);
      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('always fails');
    });
  });

  describe('payload formatting', () => {
    it('should format all notification types correctly', async () => {
      const types = [
        'order-confirmation',
        'order-status-update',
        'user-welcome',
        'user-updated',
        'system-alert',
      ] as const;

      for (const type of types) {
        transport.clearPostedWebhooks();
        const payload = makePayload({ type, id: `notif-${type}` });
        await adapter.send(payload);

        const posted = transport.getPostedWebhooks();
        expect(posted).toHaveLength(1);
        expect(posted[0]?.body.type).toBe(type);
      }
    });

    it('should include metadata in the request body', async () => {
      const payload = makePayload({ metadata: { orderId: 'ord-42', source: 'api' } });
      await adapter.send(payload);

      const posted = transport.getPostedWebhooks();
      expect(posted[0]?.body.metadata).toEqual({ orderId: 'ord-42', source: 'api' });
    });
  });

  describe('getSentWebhooks / clearSentWebhooks', () => {
    it('should return a copy of sent webhooks', async () => {
      await adapter.send(makePayload());
      const sent = adapter.getSentWebhooks();
      sent.pop(); // mutate the copy
      expect(adapter.getSentWebhooks()).toHaveLength(1);
    });

    it('should clear sent webhooks', async () => {
      await adapter.send(makePayload());
      adapter.clearSentWebhooks();
      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  describe('InMemoryWebhookTransport', () => {
    it('should store and return posted webhooks', async () => {
      const body: WebhookRequestBody = {
        notificationId: 'notif-test',
        type: 'system-alert',
        channel: 'webhook',
        recipient: 'https://test.com/hook',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
        metadata: {},
        createdAt: new Date().toISOString(),
      };

      const result = await transport.post('https://test.com/hook', body, {});
      expect(result.success).toBe(true);
      expect(result.statusCode).toBe(200);
      expect(transport.getPostedWebhooks()).toHaveLength(1);
      expect(transport.getPostedWebhooks()[0]?.url).toBe('https://test.com/hook');
    });

    it('should clear stored webhooks', async () => {
      const body: WebhookRequestBody = {
        notificationId: 'n',
        type: 'system-alert',
        channel: 'webhook',
        recipient: 'https://x.com',
        subject: 'X',
        body: '',
        priority: 'normal',
        metadata: {},
        createdAt: new Date().toISOString(),
      };
      await transport.post('https://x.com', body, {});
      transport.clearPostedWebhooks();
      expect(transport.getPostedWebhooks()).toHaveLength(0);
    });

    it('should report reachable', async () => {
      expect(await transport.isReachable()).toBe(true);
    });
  });
});
